            || selectedNumberOfOffsets == null
            || selectedPartitionId < 0
            || selectedNumberOfOffsets <= 0) {
          throw new KlawException(TOPICS_ERR_115);
        }
      }
      topicEvents =
          clusterApiService.getTopicEvents(
              kwClusters.getBootstrapServers(),
